(window.webpackJsonp=window.webpackJsonp||[]).push([[102],{185:function(t,e,n){"use strict";n.r(e);var a=n(0),i=Object(a.a)({},function(){this.$createElement;this._self._c;return this._m(0)},[function(){var t=this,e=t.$createElement,n=t._self._c||e;return n("div",{staticClass:"content"},[n("h2",{attrs:{id:"title-不去会死！date-2017-05-15-10-00categories-阅读tags-thinking"}},[n("a",{staticClass:"header-anchor",attrs:{href:"#title-不去会死！date-2017-05-15-10-00categories-阅读tags-thinking","aria-hidden":"true"}},[t._v("#")]),t._v(" title: 不去会死！\ndate: 2017-05-15 10:00\ncategories: 阅读\ntags: thinking")]),t._v(" "),n("p",[n("img",{attrs:{src:"http://7xopm5.com1.z0.glb.clouddn.com/2017/04/20/4996dbbba098cdc3e7f8b52bda4b8011.jpg",alt:"不去会死！",title:"不去会死！"}})]),t._v(" "),n("p",[t._v("到不了的都叫远方。\n"),t._v("\n大概是看的书比较少（当然这里不包括课本），我能清楚地记得每本书是在什么时候看的。这本书是在前年（15年）的这个时候看的。那会儿刚换新工作不久，为了不在路上浪费太多时间我搬到了公司附近。现在想来那时确实太冒险，试用期都还没过呢。我现在不太记得试用期是几个月了，就当是三个月吧，这样想心里会好受点。")]),t._v(" "),n("p",[t._v("我不知道出于什么原因，公司一直没给我转正，期间我也口头上询问过。开始还有几分期待，后来就产生了非走不可的念头了。可笑的是当我要离职时，才想到要给我转正，或许这只是他们的客套话而已。就好像")]),t._v(" "),n("p",[t._v("这四个月是痛苦的，住的是几平米的小隔间，不开空调房间总有股怪味道，感觉都要呼吸不过来，房租还占了工资的四分之一。与其它隔间没有交流。当一个人躯体不自由时")]),t._v(" "),n("p",[t._v("书是一个人日本小伙写的，作者从小就想‘环游世界’，该书记录了作者从北美洲开始顺时针骑车环绕世界寻找自己心中的‘世界第一’的旅程，旅程预期三年半实际七年半，文字朴实， 书中偶有作者旅行中的照片与素描。")]),t._v(" "),n("p",[t._v("说实话环游世界的‘环’我此刻才领会到是什么意思，‘环’只是形成一个‘圈’，并不是每一寸土地都去涉足，就好比我们环大鹏半岛一样。所以如果不是沿着世界走了一圈，这个‘环’是要带引号的。\n其实我不想写这些东西的，今年我真的是特别忙，但一想到 "),n("strong",[t._v("读书不思考好比不消化")]),t._v(" 就觉得还是写写吧，只要起早一点睡晚一点时间就出来了。")]),t._v(" "),n("p",[t._v("书读的少，但也有几本，为什么先‘消化’这一本，是前段时间看好看到之前的一个同事也在读这本，也是我也有想去的远方。这本书是三年前的读的了，书中的内容大多已忘记，那颗追随远方的心却一直躁动着。")]),t._v(" "),n("p",[t._v("14 年的时候，我也信誓旦旦说后年（16年）要从深圳开始骑行一趟西藏，甚至还去搜了搜什么时候去比较合适，然而我出深圳的次数也可以屈指可数，当然不是我不想去了，只是不是每个人都有说走就走的勇气和资本，我只有等待有勇气和够资本的那天了，虽然不知那天会否到来，但这并不表示我支持贾平凹先生所认为的‘风景什么时候去看都一样’，相反在不同时刻去风景和人都是不一样的，风景有可能不再了，人或许心境变了。")]),t._v(" "),n("p",[t._v("我虽然想去西藏，但是我从没做过准备，唯一的准备就是看了下什么时候去比较合适，小伙伴也笑我这样的体质还想去西藏。石田从小的梦想就是环游世界，在不大的时候就已经有‘环游和歌山县一周’、‘近一周’、‘环游日本一周’的经历。其实我也想过环台湾岛一周，海南岛一周。")]),t._v(" "),n("p",[t._v("什么想去西藏，我也说不清楚，只是觉得这辈子我要那里一次，似乎那里是流浪的终点，或许是受影视剧的影响吧，我也确实把《转山》看了两遍。有或许是随众心里吧，每个人向往自由的人，都想去那里。")])])}],!1,null,null,null);e.default=i.exports}}]);